CommandSettingConfig = {}
CommandSettingConfig.Config = {}

function CommandSettingConfig:init(config)
    for _, vConfig in pairs(config) do
        local data = {}
        data.id = tostring(vConfig.id)
        data.currencyId = tonumber(vConfig.currencyId)
        data.price = tonumber(vConfig.price)
        data.icon = tostring(vConfig.icon)
        data.text = tostring(vConfig.text)
        data.duration = tonumber(vConfig.duration)
        data.perspectiveTime = tonumber(vConfig.perspectiveTime)
        data.effectId = tonumber(vConfig.effectId)
        self.Config[tonumber(data.id)] = data
    end
end

function CommandSettingConfig:getConfigById(id)
    return self.Config[tonumber(id)]
end

function CommandSettingConfig:getAllConfig()
    return self.Config
end

CommandSettingConfig:init(FileUtil.getConfigFromCsv("setting/CommandSetting.csv"))

